import React, { useState, useMemo, useEffect } from 'react';
import {
  Coffee,
  Calculator,
  CheckSquare,
  TrendingUp,
  Sparkles,
  Trash2,
  Plus,
  BarChart2,
  Save,
  Copy,
  Layout,
  RefreshCw
} from 'lucide-react';

import { DEFAULT_CONFIG, INITIAL_TODOS, PLAN_PRESETS } from './constants';
import { GlobalConfig, MonthlyData, TodoItem, CafeUnitCosts, Scenario } from './types';
import { DashboardTab } from './components/DashboardTab';
import { PlannerTab } from './components/PlannerTab';
import { TodoTab } from './components/TodoTab';
import { ComparisonTab } from './components/ComparisonTab';

enum Tab {
  DASHBOARD = 'dashboard',
  PLANNER = 'planner',
  COMPARISON = 'comparison',
  TODO = 'todo',
}

const WEEKDAY_MONTHLY_RATE = 2156880; 
const WEEKEND_MONTHLY_RATE = 861200;  

// Helper for unique IDs (crypto.randomUUID can fail in non-secure contexts)
const generateId = () => Math.random().toString(36).substring(2, 11);

export default function App() {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.DASHBOARD);

  // Set "카페 집중형" as the default preset
  const [config, setConfig] = useState<GlobalConfig>(() => {
    const preset = PLAN_PRESETS["카페 집중형"];
    return { ...DEFAULT_CONFIG, ...preset };
  });

  // FIXED: Initialize state lazily from localStorage to ensure data is available on first render
  const [scenarios, setScenarios] = useState<Scenario[]>(() => {
    try {
      const saved = localStorage.getItem('terrazza_scenarios');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scenarios from localStorage", e);
      return [];
    }
  });

  const [activeScenarioId, setActiveScenarioId] = useState<string | null>(null);
  const [todos, setTodos] = useState<TodoItem[]>(INITIAL_TODOS);
  const [projectionMonths, setProjectionMonths] = useState(12);

  // FIXED: Automatically persist scenarios to localStorage whenever state changes
  useEffect(() => {
    try {
      localStorage.setItem('terrazza_scenarios', JSON.stringify(scenarios));
    } catch (e) {
      console.error("Failed to save scenarios to localStorage", e);
    }
  }, [scenarios]);

  const saveCurrentScenario = (name: string) => {
    const newScenario: Scenario = {
      id: generateId(),
      name,
      config: JSON.parse(JSON.stringify(config)),
      timestamp: Date.now()
    };
    // Update state, useEffect will handle localStorage
    setScenarios(prev => [...prev, newScenario]);
    setActiveScenarioId(newScenario.id);
  };

  const updateCurrentScenario = () => {
    if (!activeScenarioId) return;
    setScenarios(prev => prev.map(s => 
      s.id === activeScenarioId 
        ? { ...s, config: JSON.parse(JSON.stringify(config)), timestamp: Date.now() }
        : s
    ));
    alert("현재 계획이 업데이트되었습니다.");
  };

  const applyPreset = (presetName: string) => {
    const preset = PLAN_PRESETS[presetName];
    if (preset) {
      // Deep merge the preset into current config
      setConfig(prev => ({ ...prev, ...preset }));
      setActiveScenarioId(null);
    }
  };

  const loadScenario = (id: string) => {
    const scenario = scenarios.find(s => s.id === id);
    if (scenario) {
      setConfig(JSON.parse(JSON.stringify(scenario.config)));
      setActiveScenarioId(id);
    }
  };

  const deleteScenario = (id: string) => {
    if (window.confirm("정말 이 계획을 삭제하시겠습니까?")) {
      setScenarios(prev => prev.filter(s => s.id !== id));
      if (activeScenarioId === id) setActiveScenarioId(null);
    }
  };

  const cafeUnitCosts: CafeUnitCosts = useMemo(() => {
    const { beanPricePerKg, milkPricePerL, iceRatio, takeoutRatio } = config.cafe;
    const s = config.cafeSupplies;

    const bean = (beanPricePerKg / 1000) * s.beanGrams;
    const milk = (milkPricePerL / 1000) * s.milkMl;
    const water = s.water;
    const ice = s.ice;
    const syrup = s.syrup;

    const getMenuCost = (menu: 'am' | 'lt' | 'sl', type: 'to' | 'st', temp: 'h' | 'i') => {
      let ing = bean;
      if (menu === 'am') ing += water;
      else if (menu === 'lt') ing += milk;
      else ing += milk + syrup;

      if (temp === 'i') ing += ice;

      let pkg = 0;
      if (type === 'to') {
        pkg = temp === 'h' 
          ? (s.hotCup + s.hotLid + s.stick + s.holder + s.carrier + s.wipe + s.napkin) 
          : (s.iceCup + s.iceLid + s.straw + s.holder + s.carrier + s.wipe + s.napkin);
      } else {
        pkg = s.wipe + s.napkin + s.dishwashing + (temp === 'h' ? s.stick : s.straw);
      }
      return ing + pkg;
    };

    const products = {
      takeout: {
        hot: {
          americano: getMenuCost('am', 'to', 'h'),
          latte: getMenuCost('lt', 'to', 'h'),
          syrupLatte: getMenuCost('sl', 'to', 'h'),
        },
        ice: {
          americano: getMenuCost('am', 'to', 'i'),
          latte: getMenuCost('lt', 'to', 'i'),
          syrupLatte: getMenuCost('sl', 'to', 'i'),
        }
      },
      store: {
        hot: {
          americano: getMenuCost('am', 'st', 'h'),
          latte: getMenuCost('lt', 'st', 'h'),
          syrupLatte: getMenuCost('sl', 'st', 'h'),
        },
        ice: {
          americano: getMenuCost('am', 'st', 'i'),
          latte: getMenuCost('lt', 'st', 'i'),
          syrupLatte: getMenuCost('sl', 'st', 'i'),
        }
      }
    };

    const calcWeighted = (m: 'americano' | 'latte' | 'syrupLatte') => {
      const toH = products.takeout.hot[m];
      const toI = products.takeout.ice[m];
      const stH = products.store.hot[m];
      const stI = products.store.ice[m];

      const toWeighted = toI * iceRatio + toH * (1 - iceRatio);
      const stWeighted = stI * iceRatio + stH * (1 - iceRatio);
      return toWeighted * takeoutRatio + stWeighted * (1 - takeoutRatio);
    };

    return {
      unitCosts: { bean, milk, water, ice, syrup },
      finalCostAmericano: calcWeighted('americano'),
      finalCostLatte: calcWeighted('latte'),
      finalCostSyrupLatte: calcWeighted('syrupLatte'),
      products
    };
  }, [config.cafe, config.cafeSupplies]);

  const calculateFinancials = (cfg: GlobalConfig, uc: CafeUnitCosts) => {
    const { seatCount, operatingHours, stayDuration, turnoverTarget, ratioAmericano, ratioLatte, ratioSyrupLatte, avgPriceAmericano, avgPriceLatte, avgPriceSyrupLatte, operatingDays: cafeDays } = cfg.cafe;
    const { hourlyRate, hoursPerDay, operatingDays: spaceDays, utilizationRate } = cfg.space;
    const { avgTicketPrice, dailyTables, operatingDays: wineDays, costOfGoodsSoldRate } = cfg.wine;
    const { weekdayStaff, weekendStaff, additionalLabor, utilities, internet, marketing, maintenance, misc } = cfg.fixed;

    const safeStayDuration = stayDuration > 0 ? stayDuration : 1;
    const maxDailyCapacity = seatCount * (operatingHours / safeStayDuration);
    const salesCount = Math.round(maxDailyCapacity * turnoverTarget);

    const laborCost = (weekdayStaff * WEEKDAY_MONTHLY_RATE) + (weekendStaff * WEEKEND_MONTHLY_RATE) + additionalLabor;

    const weightedAvgPrice = avgPriceAmericano * ratioAmericano + avgPriceLatte * ratioLatte + avgPriceSyrupLatte * ratioSyrupLatte;
    const weightedAvgCost = uc.finalCostAmericano * ratioAmericano + uc.finalCostLatte * ratioLatte + uc.finalCostSyrupLatte * ratioSyrupLatte;

    const cafeRevenue = weightedAvgPrice * salesCount * cafeDays;
    const cafeCOGS = weightedAvgCost * salesCount * cafeDays;
    const spaceRevenue = hourlyRate * hoursPerDay * utilizationRate * spaceDays;
    const wineRevenue = avgTicketPrice * dailyTables * wineDays;
    const wineCOGS = wineRevenue * costOfGoodsSoldRate;

    const totalRevenue = cafeRevenue + spaceRevenue + wineRevenue;
    const totalCOGS = cafeCOGS + wineCOGS;
    const totalFixed = laborCost + utilities + internet + marketing + maintenance + misc;
    const netProfit = (totalRevenue - totalCOGS) - totalFixed;
    const totalInvestment = Object.values(cfg.initial).reduce((a, b) => a + b, 0);

    return { totalRevenue, netProfit, totalInvestment, salesCount, cafeRevenue, spaceRevenue, wineRevenue, laborCost, totalFixed, cafeCOGS, wineCOGS, totalCOGS };
  };

  const currentFinancials = useMemo(() => calculateFinancials(config, cafeUnitCosts), [config, cafeUnitCosts]);

  const monthlyData: MonthlyData[] = useMemo(() => {
    const data: MonthlyData[] = [];
    let cumulativeProfit = -currentFinancials.totalInvestment;

    for (let m = 1; m <= projectionMonths; m++) {
      cumulativeProfit += currentFinancials.netProfit;
      data.push({
        month: m,
        cafeRevenue: currentFinancials.cafeRevenue,
        spaceRevenue: currentFinancials.spaceRevenue,
        wineRevenue: currentFinancials.wineRevenue,
        revenue: currentFinancials.totalRevenue,
        cafeCOGS: currentFinancials.cafeCOGS,
        wineCOGS: currentFinancials.wineCOGS,
        laborCost: currentFinancials.laborCost,
        utilityCost: config.fixed.utilities,
        otherFixedCost: config.fixed.marketing + config.fixed.internet + config.fixed.maintenance + config.fixed.misc,
        cogs: currentFinancials.totalCOGS,
        grossProfit: currentFinancials.totalRevenue - currentFinancials.totalCOGS,
        fixedCosts: currentFinancials.totalFixed,
        netProfit: currentFinancials.netProfit,
        cumulativeProfit,
      });
    }
    return data;
  }, [currentFinancials, projectionMonths, config]);

  const bepMonth = useMemo(() => {
    const match = monthlyData.find(d => d.cumulativeProfit >= 0);
    return match ? `M+${match.month}` : '측정 불가';
  }, [monthlyData]);

  const calculateFinancialsForScenario = (cfg: GlobalConfig) => {
    const tempUc = (() => {
      const { beanPricePerKg, milkPricePerL, iceRatio, takeoutRatio } = cfg.cafe;
      const s = cfg.cafeSupplies;
      const bean = (beanPricePerKg / 1000) * s.beanGrams;
      const milk = (milkPricePerL / 1000) * s.milkMl;
      const water = s.water;
      const ice = s.ice;
      const syrup = s.syrup;

      const getMenuCost = (menu: 'am' | 'lt' | 'sl', type: 'to' | 'st', temp: 'h' | 'i') => {
        let ing = bean;
        if (menu === 'am') ing += water; else if (menu === 'lt') ing += milk; else ing += milk + syrup;
        if (temp === 'i') ing += ice;
        let pkg = 0;
        if (type === 'to') {
          pkg = temp === 'h' ? (s.hotCup + s.hotLid + s.stick + s.holder + s.carrier + s.wipe + s.napkin) : (s.iceCup + s.iceLid + s.straw + s.holder + s.carrier + s.wipe + s.napkin);
        } else {
          pkg = s.wipe + s.napkin + s.dishwashing + (temp === 'h' ? s.stick : s.straw);
        }
        return ing + pkg;
      };

      const calcWeighted = (m: 'am' | 'lt' | 'sl') => {
        const toH = getMenuCost(m, 'to', 'h');
        const toI = getMenuCost(m, 'to', 'i');
        const stH = getMenuCost(m, 'st', 'h');
        const stI = getMenuCost(m, 'st', 'i');
        const toWeighted = toI * iceRatio + toH * (1 - iceRatio);
        const stWeighted = stI * iceRatio + stH * (1 - iceRatio);
        return toWeighted * takeoutRatio + stWeighted * (1 - takeoutRatio);
      };

      return {
        finalCostAmericano: calcWeighted('am'),
        finalCostLatte: calcWeighted('lt'),
        finalCostSyrupLatte: calcWeighted('sl'),
      };
    })();

    const fin = calculateFinancials(cfg, tempUc as any);
    return {
      totalRevenue: fin.totalRevenue,
      netProfit: fin.netProfit,
      totalInvestment: fin.totalInvestment
    };
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] font-sans text-[#3e2723]">
      <header className="bg-white border-b border-orange-100 sticky top-0 z-50 shadow-sm backdrop-blur-md bg-white/90">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center space-x-4">
              <div className="p-2.5 bg-[#5d4037] rounded-xl shadow-lg">
                <Layout className="text-white" size={24} />
              </div>
              <div className="border-l border-orange-100 pl-4 py-1">
                <span className="font-bold text-lg tracking-tight block leading-tight text-[#5d4037]">Terrazza Lounge</span>
                <span className="text-[10px] text-orange-600 font-black uppercase tracking-[0.2em]">Business Planner</span>
              </div>
            </div>

            <nav className="flex space-x-1 bg-orange-50/70 p-1 rounded-xl">
              {[
                { id: Tab.DASHBOARD, label: '대시보드', icon: <TrendingUp size={16} /> },
                { id: Tab.PLANNER, label: '상세 설정', icon: <Calculator size={16} /> },
                { id: Tab.COMPARISON, label: '계획 비교', icon: <Copy size={16} /> },
                { id: Tab.TODO, label: '준비물', icon: <CheckSquare size={16} /> },
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as Tab)}
                  className={`flex items-center space-x-2 px-3 sm:px-4 py-2 rounded-lg text-sm font-bold transition-all duration-300 ${activeTab === tab.id ? 'bg-[#5d4037] text-white shadow-md' : 'text-slate-500 hover:text-[#5d4037] hover:bg-white'}`}
                >
                  {tab.icon}
                  <span className="hidden lg:inline">{tab.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>

        <div className="bg-[#fff9f5] border-b border-orange-100 py-2.5">
          <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-3">
            <div className="flex items-center gap-3 w-full md:w-auto overflow-hidden">
              <span className="text-[9px] font-black text-orange-400 uppercase tracking-widest whitespace-nowrap">Plan Presets:</span>
              <div className="flex gap-1.5 overflow-x-auto pb-1 md:pb-0 scrollbar-hide">
                {Object.keys(PLAN_PRESETS).map(name => (
                  <button 
                    key={name}
                    onClick={() => applyPreset(name)}
                    className="px-3 py-1 bg-white border border-orange-100 rounded-full text-[10px] font-bold text-[#5d4037] hover:border-orange-500 hover:text-orange-600 transition-all shadow-sm whitespace-nowrap"
                  >
                    {name}
                  </button>
                ))}
              </div>
            </div>
            <div className="flex items-center gap-3 w-full md:w-auto border-t md:border-t-0 pt-2.5 md:pt-0 border-orange-50/50">
               <span className="text-[9px] font-black text-orange-400 uppercase tracking-widest whitespace-nowrap">Saved Plans:</span>
               <div className="flex gap-1.5 overflow-x-auto scrollbar-hide items-center">
                {scenarios.map(s => (
                  <div key={s.id} className={`flex items-center bg-white border rounded-full pl-3 pr-1 h-7 shadow-sm transition-all ${activeScenarioId === s.id ? 'border-orange-500 ring-2 ring-orange-50' : 'border-orange-100'}`}>
                    <button onClick={() => loadScenario(s.id)} className={`text-[10px] font-bold mr-1.5 ${activeScenarioId === s.id ? 'text-orange-700' : 'text-[#5d4037]'}`}>
                      {s.name}
                    </button>
                    <button onClick={() => deleteScenario(s.id)} className="p-0.5 text-orange-200 hover:text-rose-500 rounded-full hover:bg-rose-50 transition-colors"><Trash2 size={10} /></button>
                  </div>
                ))}

                <div className="flex items-center gap-1 ml-2 border-l border-orange-100 pl-2">
                   {activeScenarioId && (
                    <button 
                      onClick={updateCurrentScenario}
                      className="px-2 h-7 bg-emerald-600 text-white rounded-full text-[10px] font-bold flex items-center gap-1 shadow-sm hover:bg-emerald-700 transition-all"
                      title="현재 계획 덮어쓰기"
                    >
                      <RefreshCw size={10}/> 업데이트
                    </button>
                   )}
                   <button 
                    onClick={() => { const name = prompt("계획 이름을 입력하세요:"); if(name) saveCurrentScenario(name); }} 
                    className="px-3 h-7 bg-[#5d4037] text-white rounded-full text-[10px] font-bold flex items-center gap-1.5 shadow-sm hover:bg-[#4e342e] transition-all transform hover:-translate-y-0.5"
                   >
                    <Plus size={12}/> {activeScenarioId ? '새로 저장' : '저장'}
                   </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 pb-16">
        {activeTab === Tab.DASHBOARD && (
          <DashboardTab 
            monthlyData={monthlyData}
            totalInvestment={currentFinancials.totalInvestment}
            bepMonth={bepMonth}
          />
        )}

        {activeTab === Tab.PLANNER && (
          <PlannerTab 
            config={config}
            onConfigChange={(s, f, v) => setConfig(prev => ({...prev, [s]: {...prev[s], [f]: v}}))}
            onSupplyChange={(f, v) => setConfig(prev => ({...prev, cafeSupplies: {...prev.cafeSupplies, [f]: v}}))}
            monthlyData={monthlyData}
            dailySalesCount={currentFinancials.salesCount}
            cafeUnitCosts={cafeUnitCosts} 
            totalInvestment={currentFinancials.totalInvestment}
            calculatedLaborCost={currentFinancials.laborCost}
          />
        )}

        {activeTab === Tab.COMPARISON && (
          <ComparisonTab scenarios={scenarios} calculateFinancials={calculateFinancialsForScenario} />
        )}

        {activeTab === Tab.TODO && (
          <TodoTab todos={todos} onToggle={(id) => setTodos(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t))} />
        )}
      </main>
    </div>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import {
  Coffee,
  Calculator,
  CheckSquare,
  TrendingUp,
  Sparkles,
  Trash2,
  Plus,
  BarChart2,
  Save,
  Copy,
  Layout,
  RefreshCw,
  RotateCcw
} from 'lucide-react';

import { DEFAULT_CONFIG, INITIAL_TODOS, PLAN_PRESETS } from './constants';
import { GlobalConfig, MonthlyData, TodoItem, CafeUnitCosts, Scenario } from './types';
import { DashboardTab } from './components/DashboardTab';
import { PlannerTab } from './components/PlannerTab';
import { TodoTab } from './components/TodoTab';
import { ComparisonTab } from './components/ComparisonTab';
import { StrategyTab } from './components/StrategyTab';

enum Tab {
  DASHBOARD = 'dashboard',
  PLANNER = 'planner',
  COMPARISON = 'comparison',
  STRATEGY = 'strategy',
  TODO = 'todo',
}

const WEEKDAY_MONTHLY_RATE = 2156880; 
const WEEKEND_MONTHLY_RATE = 861200;  

// Helper for unique IDs
const generateId = () => Math.random().toString(36).substring(2, 11);

export default function App() {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.DASHBOARD);

  // FIXED: Load current draft from localStorage or fallback to default preset
  const [config, setConfig] = useState<GlobalConfig>(() => {
    try {
      const savedDraft = localStorage.getItem('terrazza_current_draft');
      if (savedDraft) {
        return JSON.parse(savedDraft);
      }
    } catch (e) {
      console.error("Failed to load draft", e);
    }
    const preset = PLAN_PRESETS["카페 집중형"];
    return { ...DEFAULT_CONFIG, ...preset };
  });

  // FIXED: Initialize scenarios lazily
  const [scenarios, setScenarios] = useState<Scenario[]>(() => {
    try {
      const saved = localStorage.getItem('terrazza_scenarios');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scenarios from localStorage", e);
      return [];
    }
  });

  const [activeScenarioId, setActiveScenarioId] = useState<string | null>(null);
  const [todos, setTodos] = useState<TodoItem[]>(INITIAL_TODOS);
  const [projectionMonths, setProjectionMonths] = useState(12);

  // FIXED: Automatically persist current draft whenever it changes
  useEffect(() => {
    try {
      localStorage.setItem('terrazza_current_draft', JSON.stringify(config));
    } catch (e) {
      console.error("Failed to save draft", e);
    }
  }, [config]);

  // FIXED: Automatically persist scenarios whenever they change
  useEffect(() => {
    try {
      localStorage.setItem('terrazza_scenarios', JSON.stringify(scenarios));
    } catch (e) {
      console.error("Failed to save scenarios to localStorage", e);
    }
  }, [scenarios]);

  const saveCurrentScenario = (name: string) => {
    if (!name.trim()) return;
    const newScenario: Scenario = {
      id: generateId(),
      name,
      config: JSON.parse(JSON.stringify(config)),
      timestamp: Date.now()
    };
    setScenarios(prev => [...prev, newScenario]);
    setActiveScenarioId(newScenario.id);
  };

  const updateCurrentScenario = () => {
    if (!activeScenarioId) return;
    setScenarios(prev => prev.map(s => 
      s.id === activeScenarioId 
        ? { ...s, config: JSON.parse(JSON.stringify(config)), timestamp: Date.now() }
        : s
    ));
    alert("현재 계획이 업데이트되었습니다.");
  };

  const applyPreset = (presetName: string) => {
    if (window.confirm(`'${presetName}' 프리셋을 적용하시겠습니까? 현재 작성 중인 내용이 변경됩니다.`)) {
      const preset = PLAN_PRESETS[presetName];
      if (preset) {
        setConfig(prev => ({ ...prev, ...preset }));
        setActiveScenarioId(null);
      }
    }
  };

  const loadScenario = (id: string) => {
    const scenario = scenarios.find(s => s.id === id);
    if (scenario) {
      if (window.confirm(`'${scenario.name}' 계획을 불러오시겠습니까?`)) {
        setConfig(JSON.parse(JSON.stringify(scenario.config)));
        setActiveScenarioId(id);
      }
    }
  };

  const deleteScenario = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm("정말 이 계획을 삭제하시겠습니까?")) {
      setScenarios(prev => prev.filter(s => s.id !== id));
      if (activeScenarioId === id) setActiveScenarioId(null);
    }
  };

  const resetConfig = () => {
    if (window.confirm("모든 설정을 초기화하시겠습니까?")) {
       const preset = PLAN_PRESETS["카페 집중형"];
       setConfig({ ...DEFAULT_CONFIG, ...preset });
       setActiveScenarioId(null);
    }
  };

  const cafeUnitCosts: CafeUnitCosts = useMemo(() => {
    const { beanPricePerKg, milkPricePerL, iceRatio, takeoutRatio } = config.cafe;
    const s = config.cafeSupplies;

    const bean = (beanPricePerKg / 1000) * s.beanGrams;
    const milk = (milkPricePerL / 1000) * s.milkMl;
    const water = s.water;
    const ice = s.ice;
    const syrup = s.syrup;

    const getMenuCost = (menu: 'am' | 'lt' | 'sl', type: 'to' | 'st', temp: 'h' | 'i') => {
      let ing = bean;
      if (menu === 'am') ing += water;
      else if (menu === 'lt') ing += milk;
      else ing += milk + syrup;

      if (temp === 'i') ing += ice;

      let pkg = 0;
      if (type === 'to') {
        pkg = temp === 'h' 
          ? (s.hotCup + s.hotLid + s.stick + s.holder + s.carrier + s.wipe + s.napkin) 
          : (s.iceCup + s.iceLid + s.straw + s.holder + s.carrier + s.wipe + s.napkin);
      } else {
        pkg = s.wipe + s.napkin + s.dishwashing + (temp === 'h' ? s.stick : s.straw);
      }
      return ing + pkg;
    };

    const products = {
      takeout: {
        hot: {
          americano: getMenuCost('am', 'to', 'h'),
          latte: getMenuCost('lt', 'to', 'h'),
          syrupLatte: getMenuCost('sl', 'to', 'h'),
        },
        ice: {
          americano: getMenuCost('am', 'to', 'i'),
          latte: getMenuCost('lt', 'to', 'i'),
          syrupLatte: getMenuCost('sl', 'to', 'i'),
        }
      },
      store: {
        hot: {
          americano: getMenuCost('am', 'st', 'h'),
          latte: getMenuCost('lt', 'st', 'h'),
          syrupLatte: getMenuCost('sl', 'st', 'h'),
        },
        ice: {
          americano: getMenuCost('am', 'st', 'i'),
          latte: getMenuCost('lt', 'st', 'i'),
          syrupLatte: getMenuCost('sl', 'st', 'i'),
        }
      }
    };

    const calcWeighted = (m: 'americano' | 'latte' | 'syrupLatte') => {
      const toH = products.takeout.hot[m];
      const toI = products.takeout.ice[m];
      const stH = products.store.hot[m];
      const stI = products.store.ice[m];

      const toWeighted = toI * iceRatio + toH * (1 - iceRatio);
      const stWeighted = stI * iceRatio + stH * (1 - iceRatio);
      return toWeighted * takeoutRatio + stWeighted * (1 - takeoutRatio);
    };

    return {
      unitCosts: { bean, milk, water, ice, syrup },
      finalCostAmericano: calcWeighted('americano'),
      finalCostLatte: calcWeighted('latte'),
      finalCostSyrupLatte: calcWeighted('syrupLatte'),
      products
    };
  }, [config.cafe, config.cafeSupplies]);

  const calculateFinancials = (cfg: GlobalConfig, uc: CafeUnitCosts) => {
    const { seatCount, operatingHours, stayDuration, turnoverTarget, ratioAmericano, ratioLatte, ratioSyrupLatte, avgPriceAmericano, avgPriceLatte, avgPriceSyrupLatte, operatingDays: cafeDays } = cfg.cafe;
    const { hourlyRate, hoursPerDay, operatingDays: spaceDays, utilizationRate } = cfg.space;
    const { avgTicketPrice, dailyTables, operatingDays: wineDays, costOfGoodsSoldRate } = cfg.wine;
    const { weekdayStaff, weekendStaff, additionalLabor, utilities, internet, marketing, maintenance, misc } = cfg.fixed;

    const safeStayDuration = stayDuration > 0 ? stayDuration : 1;
    const maxDailyCapacity = seatCount * (operatingHours / safeStayDuration);
    const salesCount = Math.round(maxDailyCapacity * turnoverTarget);

    const laborCost = (weekdayStaff * WEEKDAY_MONTHLY_RATE) + (weekendStaff * WEEKEND_MONTHLY_RATE) + additionalLabor;

    const weightedAvgPrice = avgPriceAmericano * ratioAmericano + avgPriceLatte * ratioLatte + avgPriceSyrupLatte * ratioSyrupLatte;
    const weightedAvgCost = uc.finalCostAmericano * ratioAmericano + uc.finalCostLatte * ratioLatte + uc.finalCostSyrupLatte * ratioSyrupLatte;

    const cafeRevenue = weightedAvgPrice * salesCount * cafeDays;
    const cafeCOGS = weightedAvgCost * salesCount * cafeDays;
    const spaceRevenue = hourlyRate * hoursPerDay * utilizationRate * spaceDays;
    const wineRevenue = avgTicketPrice * dailyTables * wineDays;
    const wineCOGS = wineRevenue * costOfGoodsSoldRate;

    const totalRevenue = cafeRevenue + spaceRevenue + wineRevenue;
    const totalCOGS = cafeCOGS + wineCOGS;
    const totalFixed = laborCost + utilities + internet + marketing + maintenance + misc;
    const netProfit = (totalRevenue - totalCOGS) - totalFixed;
    const totalInvestment = Object.values(cfg.initial).reduce((a, b) => a + b, 0);

    return { totalRevenue, netProfit, totalInvestment, salesCount, cafeRevenue, spaceRevenue, wineRevenue, laborCost, totalFixed, cafeCOGS, wineCOGS, totalCOGS };
  };

  const currentFinancials = useMemo(() => calculateFinancials(config, cafeUnitCosts), [config, cafeUnitCosts]);

  const monthlyData: MonthlyData[] = useMemo(() => {
    const data: MonthlyData[] = [];
    let cumulativeProfit = -currentFinancials.totalInvestment;

    for (let m = 1; m <= projectionMonths; m++) {
      cumulativeProfit += currentFinancials.netProfit;
      data.push({
        month: m,
        cafeRevenue: currentFinancials.cafeRevenue,
        spaceRevenue: currentFinancials.spaceRevenue,
        wineRevenue: currentFinancials.wineRevenue,
        revenue: currentFinancials.totalRevenue,
        cafeCOGS: currentFinancials.cafeCOGS,
        wineCOGS: currentFinancials.wineCOGS,
        laborCost: currentFinancials.laborCost,
        utilityCost: config.fixed.utilities,
        otherFixedCost: config.fixed.marketing + config.fixed.internet + config.fixed.maintenance + config.fixed.misc,
        cogs: currentFinancials.totalCOGS,
        grossProfit: currentFinancials.totalRevenue - currentFinancials.totalCOGS,
        fixedCosts: currentFinancials.totalFixed,
        netProfit: currentFinancials.netProfit,
        cumulativeProfit,
      });
    }
    return data;
  }, [currentFinancials, projectionMonths, config]);

  const bepMonth = useMemo(() => {
    const match = monthlyData.find(d => d.cumulativeProfit >= 0);
    return match ? `M+${match.month}` : '측정 불가';
  }, [monthlyData]);

  // Helper for Comparison Tab
  const calculateFinancialsForScenario = (cfg: GlobalConfig) => {
    // Re-calculate unit costs locally for the scenario
    const tempUc = (() => {
      const { beanPricePerKg, milkPricePerL, iceRatio, takeoutRatio } = cfg.cafe;
      const s = cfg.cafeSupplies;
      const bean = (beanPricePerKg / 1000) * s.beanGrams;
      const milk = (milkPricePerL / 1000) * s.milkMl;
      const water = s.water;
      const ice = s.ice;
      const syrup = s.syrup;
      const getMenuCost = (menu: string, type: string, temp: string) => {
        let ing = bean;
        if (menu === 'am') ing += water; else if (menu === 'lt') ing += milk; else ing += milk + syrup;
        if (temp === 'i') ing += ice;
        let pkg = 0;
        if (type === 'to') {
            pkg = temp === 'h' ? (s.hotCup + s.hotLid + s.stick + s.holder + s.carrier + s.wipe + s.napkin) : (s.iceCup + s.iceLid + s.straw + s.holder + s.carrier + s.wipe + s.napkin);
        } else {
            pkg = s.wipe + s.napkin + s.dishwashing + (temp === 'h' ? s.stick : s.straw);
        }
        return ing + pkg;
      };

      const calcWeighted = (m: 'am' | 'lt' | 'sl') => {
          const toH = getMenuCost(m, 'to', 'h');
          const toI = getMenuCost(m, 'to', 'i');
          const stH = getMenuCost(m, 'st', 'h');
          const stI = getMenuCost(m, 'st', 'i');
          return (toI * iceRatio + toH * (1 - iceRatio)) * takeoutRatio + (stI * iceRatio + stH * (1 - iceRatio)) * (1 - takeoutRatio);
      };
      return {
        finalCostAmericano: calcWeighted('am'),
        finalCostLatte: calcWeighted('lt'),
        finalCostSyrupLatte: calcWeighted('sl'),
      };
    })();

    const fin = calculateFinancials(cfg, tempUc as any);
    return {
      totalRevenue: fin.totalRevenue,
      netProfit: fin.netProfit,
      totalInvestment: fin.totalInvestment
    };
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] font-sans text-[#3e2723]">
      <header className="bg-white border-b border-orange-100 sticky top-0 z-50 shadow-sm backdrop-blur-md bg-white/90">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center space-x-4">
              <div className="p-2.5 bg-[#5d4037] rounded-xl shadow-lg">
                <Layout className="text-white" size={24} />
              </div>
              <div className="border-l border-orange-100 pl-4 py-1">
                <span className="font-bold text-lg tracking-tight block leading-tight text-[#5d4037]">Terrazza Lounge</span>
                <span className="text-[10px] text-orange-600 font-black uppercase tracking-[0.2em]">Business Planner</span>
              </div>
            </div>

            <nav className="flex space-x-1 bg-orange-50/70 p-1 rounded-xl overflow-x-auto">
              {[
                { id: Tab.DASHBOARD, label: '대시보드', icon: <TrendingUp size={16} /> },
                { id: Tab.PLANNER, label: '상세 설정', icon: <Calculator size={16} /> },
                { id: Tab.COMPARISON, label: '계획 비교', icon: <Copy size={16} /> },
                { id: Tab.STRATEGY, label: 'AI 전략', icon: <Sparkles size={16} /> },
                { id: Tab.TODO, label: '준비물', icon: <CheckSquare size={16} /> },
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as Tab)}
                  className={`flex items-center space-x-2 px-3 sm:px-4 py-2 rounded-lg text-sm font-bold transition-all duration-300 whitespace-nowrap ${activeTab === tab.id ? 'bg-[#5d4037] text-white shadow-md' : 'text-slate-500 hover:text-[#5d4037] hover:bg-white'}`}
                >
                  {tab.icon}
                  <span className="hidden lg:inline">{tab.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>

        <div className="bg-[#fff9f5] border-b border-orange-100 py-2.5">
          <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-3">
            <div className="flex items-center gap-3 w-full md:w-auto overflow-hidden">
              <span className="text-[9px] font-black text-orange-400 uppercase tracking-widest whitespace-nowrap">Plan Presets:</span>
              <div className="flex gap-1.5 overflow-x-auto pb-1 md:pb-0 scrollbar-hide">
                {Object.keys(PLAN_PRESETS).map(name => (
                  <button 
                    key={name}
                    onClick={() => applyPreset(name)}
                    className="px-3 py-1 bg-white border border-orange-100 rounded-full text-[10px] font-bold text-[#5d4037] hover:border-orange-500 hover:text-orange-600 transition-all shadow-sm whitespace-nowrap"
                  >
                    {name}
                  </button>
                ))}
                <button 
                  onClick={resetConfig}
                  className="px-3 py-1 bg-slate-100 border border-slate-200 rounded-full text-[10px] font-bold text-slate-500 hover:bg-slate-200 transition-all shadow-sm whitespace-nowrap flex items-center gap-1"
                >
                  <RotateCcw size={10} /> 초기화
                </button>
              </div>
            </div>
            <div className="flex items-center gap-3 w-full md:w-auto border-t md:border-t-0 pt-2.5 md:pt-0 border-orange-50/50">
               <span className="text-[9px] font-black text-orange-400 uppercase tracking-widest whitespace-nowrap">Saved Plans:</span>
               <div className="flex gap-1.5 overflow-x-auto scrollbar-hide items-center">
                {scenarios.map(s => (
                  <div key={s.id} className={`flex items-center bg-white border rounded-full pl-3 pr-1 h-7 shadow-sm transition-all group ${activeScenarioId === s.id ? 'border-orange-500 ring-2 ring-orange-50' : 'border-orange-100'}`}>
                    <button onClick={() => loadScenario(s.id)} className={`text-[10px] font-bold mr-1.5 whitespace-nowrap ${activeScenarioId === s.id ? 'text-orange-700' : 'text-[#5d4037]'}`}>
                      {s.name}
                    </button>
                    <button onClick={(e) => deleteScenario(s.id, e)} className="p-0.5 text-orange-200 hover:text-rose-500 rounded-full hover:bg-rose-50 transition-colors"><Trash2 size={10} /></button>
                  </div>
                ))}

                <div className="flex items-center gap-1 ml-2 border-l border-orange-100 pl-2">
                   {activeScenarioId && (
                    <button 
                      onClick={updateCurrentScenario}
                      className="px-2 h-7 bg-emerald-600 text-white rounded-full text-[10px] font-bold flex items-center gap-1 shadow-sm hover:bg-emerald-700 transition-all whitespace-nowrap"
                      title="현재 계획 덮어쓰기"
                    >
                      <RefreshCw size={10}/> 업데이트
                    </button>
                   )}
                   <button 
                    onClick={() => { const name = prompt("새로운 계획 이름을 입력하세요:"); if(name) saveCurrentScenario(name); }} 
                    className="px-3 h-7 bg-[#5d4037] text-white rounded-full text-[10px] font-bold flex items-center gap-1.5 shadow-sm hover:bg-[#4e342e] transition-all transform hover:-translate-y-0.5 whitespace-nowrap"
                   >
                    <Plus size={12}/> {activeScenarioId ? '새로 저장' : '저장'}
                   </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 pb-16">
        {activeTab === Tab.DASHBOARD && (
          <DashboardTab 
            monthlyData={monthlyData}
            totalInvestment={currentFinancials.totalInvestment}
            bepMonth={bepMonth}
          />
        )}

        {activeTab === Tab.PLANNER && (
          <PlannerTab 
            config={config}
            onConfigChange={(s, f, v) => setConfig(prev => ({...prev, [s]: {...prev[s], [f]: v}}))}
            onSupplyChange={(f, v) => setConfig(prev => ({...prev, cafeSupplies: {...prev.cafeSupplies, [f]: v}}))}
            monthlyData={monthlyData}
            dailySalesCount={currentFinancials.salesCount}
            cafeUnitCosts={cafeUnitCosts} 
            totalInvestment={currentFinancials.totalInvestment}
            calculatedLaborCost={currentFinancials.laborCost}
          />
        )}

        {/* FIXED: Passed currentConfig to ComparisonTab to allow real-time comparison */}
        {activeTab === Tab.COMPARISON && (
          <ComparisonTab 
            scenarios={scenarios} 
            currentConfig={config}
            calculateFinancials={calculateFinancialsForScenario} 
          />
        )}

        {activeTab === Tab.STRATEGY && (
          <StrategyTab config={config} financials={currentFinancials} bepMonth={bepMonth} />
        )}

        {activeTab === Tab.TODO && (
          <TodoTab todos={todos} onToggle={(id) => setTodos(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t))} />
        )}
      </main>
    </div>
  );
}

import React, { useMemo } from 'react';
import { Scenario, GlobalConfig } from '../types';
import { BarChart2, TrendingUp, DollarSign, Wallet } from 'lucide-react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Cell
} from 'recharts';

interface ComparisonTabProps {
  scenarios: Scenario[];
  currentConfig: GlobalConfig;
  calculateFinancials: (config: GlobalConfig) => {
    totalRevenue: number;
    netProfit: number;
    totalInvestment: number;
  };
}

export const ComparisonTab: React.FC<ComparisonTabProps> = ({ scenarios, currentConfig, calculateFinancials }) => {
  const comparisonData = useMemo(() => {
    // 1. Convert Saved Scenarios
    const saved = scenarios.map(s => ({
      id: s.id,
      name: s.name,
      ...calculateFinancials(s.config),
      isCurrent: false
    }));

    // 2. Add Current Draft (always included for comparison)
    // Only add if it doesn't look exactly like a saved scenario? 
    // Actually better to always show it so user knows "This is what I am editing right now".
    const current = {
      id: 'current-draft',
      name: '현재 편집 중 (Draft)',
      ...calculateFinancials(currentConfig),
      isCurrent: true
    };

    return [...saved, current].map(res => ({
      ...res,
      margin: res.totalRevenue > 0 ? (res.netProfit / res.totalRevenue) * 100 : 0,
      bep: res.netProfit > 0 ? res.totalInvestment / res.netProfit : 99 // Cap/Flag for chart
    }));
  }, [scenarios, currentConfig, calculateFinancials]);

  const formatKrw = (val: number) => `₩${Math.round(val / 10000).toLocaleString()}만`;

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Profit Comparison Chart */}
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
            <DollarSign className="text-emerald-500" size={20} /> 계획별 월 예상 순이익 비교
          </h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={comparisonData} margin={{ top: 20, right: 30, left: 0, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis hide />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  content={({active, payload}) => {
                    if (active && payload && payload.length) {
                      const data = payload[0].payload;
                      return (
                        <div className="bg-slate-900 text-white p-3 rounded-xl text-xs shadow-xl">
                          <p className="font-bold mb-1">{data.name}</p>
                          <p className="text-emerald-400">순이익: {formatKrw(data.netProfit as number)}</p>
                          {data.isCurrent && <p className="text-orange-300 mt-1 italic">* 현재 편집 중인 설정</p>}
                        </div>
                      )
                    }
                    return null;
                  }}
                />
                <Bar dataKey="netProfit" radius={[8, 8, 0, 0]} barSize={40}>
                  {comparisonData.map((entry, index) => (
                    <Cell 
                        key={`cell-${index}`} 
                        fill={entry.isCurrent ? '#f97316' : (entry.netProfit > 0 ? '#10b981' : '#f43f5e')} 
                        stroke={entry.isCurrent ? '#c2410c' : 'none'}
                        strokeWidth={entry.isCurrent ? 2 : 0}
                    />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
          <div className="text-center mt-4 flex justify-center gap-4 text-xs text-slate-500">
             <span className="flex items-center gap-1"><div className="w-3 h-3 bg-emerald-500 rounded-sm"></div> 저장된 계획</span>
             <span className="flex items-center gap-1"><div className="w-3 h-3 bg-orange-500 rounded-sm border border-orange-700"></div> 현재 편집 중 (Draft)</span>
          </div>
        </div>

        {/* BEP Comparison Chart */}
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
            <Wallet className="text-indigo-500" size={20} /> 예상 투자금 회수 기간 (개월)
          </h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={comparisonData} margin={{ top: 20, right: 30, left: 0, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis hide />
                <Tooltip 
                   cursor={{fill: '#f8fafc'}}
                   content={({active, payload}) => {
                    if (active && payload && payload.length) {
                      return (
                        <div className="bg-slate-900 text-white p-3 rounded-xl text-xs shadow-xl">
                          <p className="font-bold mb-1">{payload[0].payload.name}</p>
                          <p className="text-indigo-400">회수기간: {payload[0].value === 99 ? '측정불가' : `${Math.ceil(payload[0].value as number)}개월`}</p>
                        </div>
                      )
                    }
                    return null;
                  }}
                />
                <Bar dataKey="bep" fill="#6366f1" radius={[8, 8, 0, 0]} barSize={40}>
                     {comparisonData.map((entry, index) => (
                        <Cell 
                            key={`cell-${index}`} 
                            fill={entry.isCurrent ? '#f97316' : '#6366f1'} 
                        />
                      ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="px-8 py-6 border-b border-slate-100 flex items-center justify-between">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
            <BarChart2 className="text-indigo-600" /> 상세 데이터 비교
          </h2>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="bg-slate-50/50">
                <th className="px-8 py-5 text-left font-bold text-slate-500 uppercase tracking-wider">계획 이름</th>
                <th className="px-6 py-5 text-right font-bold text-slate-500 uppercase tracking-wider">월 매출</th>
                <th className="px-6 py-5 text-right font-bold text-slate-500 uppercase tracking-wider">월 순이익</th>
                <th className="px-6 py-5 text-center font-bold text-slate-500 uppercase tracking-wider">수익률</th>
                <th className="px-6 py-5 text-right font-bold text-slate-500 uppercase tracking-wider">투자금</th>
                <th className="px-8 py-5 text-right font-bold text-slate-500 uppercase tracking-wider">회수 시점</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {comparisonData.map((res, idx) => (
                <tr key={idx} className={`transition-colors group ${res.isCurrent ? 'bg-orange-50/30 hover:bg-orange-50' : 'hover:bg-indigo-50/20'}`}>
                  <td className="px-8 py-6">
                    <div className={`font-bold transition-colors flex items-center gap-2 ${res.isCurrent ? 'text-orange-700' : 'text-slate-900 group-hover:text-indigo-600'}`}>
                        {res.name}
                        {res.isCurrent && <span className="px-2 py-0.5 bg-orange-100 text-orange-700 text-[10px] rounded-full">DRAFT</span>}
                    </div>
                  </td>
                  <td className="px-6 py-6 text-right text-slate-700 font-semibold">{formatKrw(res.totalRevenue)}</td>
                  <td className="px-6 py-6 text-right font-black text-emerald-600">{formatKrw(res.netProfit)}</td>
                  <td className="px-6 py-6 text-center">
                    <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-bold ${res.margin > 25 ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-600'}`}>
                      {res.margin.toFixed(1)}%
                    </span>
                  </td>
                  <td className="px-6 py-6 text-right text-slate-500">{formatKrw(res.totalInvestment)}</td>
                  <td className="px-8 py-6 text-right">
                    <div className="inline-flex items-center gap-1.5 font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl">
                      <TrendingUp size={14} />
                      {res.netProfit > 0 ? `M+${Math.ceil(res.totalInvestment / res.netProfit)}` : '측정불가'}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { label: '최대 수익 계획', value: comparisonData.sort((a,b) => b.netProfit - a.netProfit)[0].name, icon: <DollarSign className="text-emerald-500"/>, bg: 'bg-emerald-50' },
          { label: '최고 마진율', value: comparisonData.sort((a,b) => b.margin - a.margin)[0].name, icon: <TrendingUp className="text-amber-500"/>, bg: 'bg-amber-50' },
          { label: '최단기 BEP', value: comparisonData.sort((a,b) => a.bep - b.bep)[0].name, icon: <Wallet className="text-indigo-500"/>, bg: 'bg-indigo-50' },
        ].map((stat, i) => (
          <div key={i} className={`p-6 rounded-3xl border border-slate-200 ${stat.bg} shadow-sm flex items-center justify-between`}>
            <div>
              <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{stat.label}</div>
              <div className="text-lg font-bold text-slate-900">{stat.value}</div>
            </div>
            <div className="bg-white p-3 rounded-2xl shadow-sm">{stat.icon}</div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import {
  Coffee,
  Calculator,
  CheckSquare,
  TrendingUp,
  Sparkles,
  Trash2,
  Plus,
  BarChart2,
  Save,
  Copy,
  Layout,
  RefreshCw,
  RotateCcw,
  BookTemplate
} from 'lucide-react';

import { DEFAULT_CONFIG, INITIAL_TODOS, PLAN_PRESETS } from './constants';
import { GlobalConfig, MonthlyData, TodoItem, CafeUnitCosts, Scenario } from './types';
import { DashboardTab } from './components/DashboardTab';
import { PlannerTab } from './components/PlannerTab';
import { TodoTab } from './components/TodoTab';
import { ComparisonTab } from './components/ComparisonTab';
import { StrategyTab } from './components/StrategyTab';

enum Tab {
  DASHBOARD = 'dashboard',
  PLANNER = 'planner',
  COMPARISON = 'comparison',
  STRATEGY = 'strategy',
  TODO = 'todo',
}

const WEEKDAY_MONTHLY_RATE = 2156880; 
const WEEKEND_MONTHLY_RATE = 861200;  

// Helper for unique IDs
const generateId = () => Math.random().toString(36).substring(2, 11);

export default function App() {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.DASHBOARD);

  // FIXED: Load current draft from localStorage or fallback to default preset
  const [config, setConfig] = useState<GlobalConfig>(() => {
    try {
      const savedDraft = localStorage.getItem('terrazza_current_draft');
      if (savedDraft) {
        return JSON.parse(savedDraft);
      }
    } catch (e) {
      console.error("Failed to load draft", e);
    }
    const preset = PLAN_PRESETS["카페 집중형"];
    return { ...DEFAULT_CONFIG, ...preset };
  });

  // FIXED: Initialize scenarios lazily
  const [scenarios, setScenarios] = useState<Scenario[]>(() => {
    try {
      const saved = localStorage.getItem('terrazza_scenarios');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load scenarios from localStorage", e);
      return [];
    }
  });

  const [activeScenarioId, setActiveScenarioId] = useState<string | null>(null);
  const [todos, setTodos] = useState<TodoItem[]>(INITIAL_TODOS);
  const [projectionMonths, setProjectionMonths] = useState(12);

  // FIXED: Automatically persist current draft whenever it changes
  useEffect(() => {
    try {
      localStorage.setItem('terrazza_current_draft', JSON.stringify(config));
    } catch (e) {
      console.error("Failed to save draft", e);
    }
  }, [config]);

  // FIXED: Automatically persist scenarios whenever they change
  useEffect(() => {
    try {
      localStorage.setItem('terrazza_scenarios', JSON.stringify(scenarios));
    } catch (e) {
      console.error("Failed to save scenarios to localStorage", e);
    }
  }, [scenarios]);

  const saveCurrentScenario = (name: string) => {
    if (!name.trim()) return;
    const newScenario: Scenario = {
      id: generateId(),
      name,
      config: JSON.parse(JSON.stringify(config)),
      timestamp: Date.now()
    };
    setScenarios(prev => [...prev, newScenario]);
    setActiveScenarioId(newScenario.id);
  };

  const updateCurrentScenario = () => {
    if (!activeScenarioId) return;
    setScenarios(prev => prev.map(s => 
      s.id === activeScenarioId 
        ? { ...s, config: JSON.parse(JSON.stringify(config)), timestamp: Date.now() }
        : s
    ));
    alert("현재 계획이 업데이트되었습니다.");
  };

  const applyPreset = (presetName: string) => {
    if (window.confirm(`'${presetName}' 모델을 적용하시겠습니까?\n현재 입력된 값들이 선택한 표준 모델 값으로 변경됩니다.`)) {
      const preset = PLAN_PRESETS[presetName];
      if (preset) {
        setConfig(prev => ({ ...prev, ...preset }));
        setActiveScenarioId(null); // Presets are start of a new draft, so detach from saved ID
      }
    }
  };

  const loadScenario = (id: string) => {
    const scenario = scenarios.find(s => s.id === id);
    if (scenario) {
      if (window.confirm(`'${scenario.name}' 계획을 불러오시겠습니까?`)) {
        setConfig(JSON.parse(JSON.stringify(scenario.config)));
        setActiveScenarioId(id);
      }
    }
  };

  const deleteScenario = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm("정말 이 계획을 삭제하시겠습니까?")) {
      setScenarios(prev => prev.filter(s => s.id !== id));
      if (activeScenarioId === id) setActiveScenarioId(null);
    }
  };

  const resetConfig = () => {
    if (window.confirm("현재 작업 중인 내용을 초기화하시겠습니까?\n저장되지 않은 변경사항은 삭제됩니다.")) {
       const preset = PLAN_PRESETS["카페 집중형"];
       setConfig({ ...DEFAULT_CONFIG, ...preset });
       setActiveScenarioId(null);
    }
  };

  const cafeUnitCosts: CafeUnitCosts = useMemo(() => {
    const { beanPricePerKg, milkPricePerL, iceRatio, takeoutRatio } = config.cafe;
    const s = config.cafeSupplies;

    const bean = (beanPricePerKg / 1000) * s.beanGrams;
    const milk = (milkPricePerL / 1000) * s.milkMl;
    const water = s.water;
    const ice = s.ice;
    const syrup = s.syrup;

    const getMenuCost = (menu: 'am' | 'lt' | 'sl', type: 'to' | 'st', temp: 'h' | 'i') => {
      let ing = bean;
      if (menu === 'am') ing += water;
      else if (menu === 'lt') ing += milk;
      else ing += milk + syrup;

      if (temp === 'i') ing += ice;

      let pkg = 0;
      if (type === 'to') {
        pkg = temp === 'h' 
          ? (s.hotCup + s.hotLid + s.stick + s.holder + s.carrier + s.wipe + s.napkin) 
          : (s.iceCup + s.iceLid + s.straw + s.holder + s.carrier + s.wipe + s.napkin);
      } else {
        pkg = s.wipe + s.napkin + s.dishwashing + (temp === 'h' ? s.stick : s.straw);
      }
      return ing + pkg;
    };

    const products = {
      takeout: {
        hot: {
          americano: getMenuCost('am', 'to', 'h'),
          latte: getMenuCost('lt', 'to', 'h'),
          syrupLatte: getMenuCost('sl', 'to', 'h'),
        },
        ice: {
          americano: getMenuCost('am', 'to', 'i'),
          latte: getMenuCost('lt', 'to', 'i'),
          syrupLatte: getMenuCost('sl', 'to', 'i'),
        }
      },
      store: {
        hot: {
          americano: getMenuCost('am', 'st', 'h'),
          latte: getMenuCost('lt', 'st', 'h'),
          syrupLatte: getMenuCost('sl', 'st', 'h'),
        },
        ice: {
          americano: getMenuCost('am', 'st', 'i'),
          latte: getMenuCost('lt', 'st', 'i'),
          syrupLatte: getMenuCost('sl', 'st', 'i'),
        }
      }
    };

    const calcWeighted = (m: 'americano' | 'latte' | 'syrupLatte') => {
      const toH = products.takeout.hot[m];
      const toI = products.takeout.ice[m];
      const stH = products.store.hot[m];
      const stI = products.store.ice[m];

      const toWeighted = toI * iceRatio + toH * (1 - iceRatio);
      const stWeighted = stI * iceRatio + stH * (1 - iceRatio);
      return toWeighted * takeoutRatio + stWeighted * (1 - takeoutRatio);
    };

    return {
      unitCosts: { bean, milk, water, ice, syrup },
      finalCostAmericano: calcWeighted('americano'),
      finalCostLatte: calcWeighted('latte'),
      finalCostSyrupLatte: calcWeighted('syrupLatte'),
      products
    };
  }, [config.cafe, config.cafeSupplies]);

  const calculateFinancials = (cfg: GlobalConfig, uc: CafeUnitCosts) => {
    const { seatCount, operatingHours, stayDuration, turnoverTarget, ratioAmericano, ratioLatte, ratioSyrupLatte, avgPriceAmericano, avgPriceLatte, avgPriceSyrupLatte, operatingDays: cafeDays } = cfg.cafe;
    const { hourlyRate, hoursPerDay, operatingDays: spaceDays, utilizationRate } = cfg.space;
    const { avgTicketPrice, dailyTables, operatingDays: wineDays, costOfGoodsSoldRate } = cfg.wine;
    const { weekdayStaff, weekendStaff, additionalLabor, utilities, internet, marketing, maintenance, misc } = cfg.fixed;

    const safeStayDuration = stayDuration > 0 ? stayDuration : 1;
    const maxDailyCapacity = seatCount * (operatingHours / safeStayDuration);
    const salesCount = Math.round(maxDailyCapacity * turnoverTarget);

    const laborCost = (weekdayStaff * WEEKDAY_MONTHLY_RATE) + (weekendStaff * WEEKEND_MONTHLY_RATE) + additionalLabor;

    const weightedAvgPrice = avgPriceAmericano * ratioAmericano + avgPriceLatte * ratioLatte + avgPriceSyrupLatte * ratioSyrupLatte;
    const weightedAvgCost = uc.finalCostAmericano * ratioAmericano + uc.finalCostLatte * ratioLatte + uc.finalCostSyrupLatte * ratioSyrupLatte;

    const cafeRevenue = weightedAvgPrice * salesCount * cafeDays;
    const cafeCOGS = weightedAvgCost * salesCount * cafeDays;
    const spaceRevenue = hourlyRate * hoursPerDay * utilizationRate * spaceDays;
    const wineRevenue = avgTicketPrice * dailyTables * wineDays;
    const wineCOGS = wineRevenue * costOfGoodsSoldRate;

    const totalRevenue = cafeRevenue + spaceRevenue + wineRevenue;
    const totalCOGS = cafeCOGS + wineCOGS;
    const totalFixed = laborCost + utilities + internet + marketing + maintenance + misc;
    const netProfit = (totalRevenue - totalCOGS) - totalFixed;
    const totalInvestment = Object.values(cfg.initial).reduce((a, b) => a + b, 0);

    return { totalRevenue, netProfit, totalInvestment, salesCount, cafeRevenue, spaceRevenue, wineRevenue, laborCost, totalFixed, cafeCOGS, wineCOGS, totalCOGS };
  };

  const currentFinancials = useMemo(() => calculateFinancials(config, cafeUnitCosts), [config, cafeUnitCosts]);

  const monthlyData: MonthlyData[] = useMemo(() => {
    const data: MonthlyData[] = [];
    let cumulativeProfit = -currentFinancials.totalInvestment;

    for (let m = 1; m <= projectionMonths; m++) {
      cumulativeProfit += currentFinancials.netProfit;
      data.push({
        month: m,
        cafeRevenue: currentFinancials.cafeRevenue,
        spaceRevenue: currentFinancials.spaceRevenue,
        wineRevenue: currentFinancials.wineRevenue,
        revenue: currentFinancials.totalRevenue,
        cafeCOGS: currentFinancials.cafeCOGS,
        wineCOGS: currentFinancials.wineCOGS,
        laborCost: currentFinancials.laborCost,
        utilityCost: config.fixed.utilities,
        otherFixedCost: config.fixed.marketing + config.fixed.internet + config.fixed.maintenance + config.fixed.misc,
        cogs: currentFinancials.totalCOGS,
        grossProfit: currentFinancials.totalRevenue - currentFinancials.totalCOGS,
        fixedCosts: currentFinancials.totalFixed,
        netProfit: currentFinancials.netProfit,
        cumulativeProfit,
      });
    }
    return data;
  }, [currentFinancials, projectionMonths, config]);

  const bepMonth = useMemo(() => {
    const match = monthlyData.find(d => d.cumulativeProfit >= 0);
    return match ? `M+${match.month}` : '측정 불가';
  }, [monthlyData]);

  // Helper for Comparison Tab
  const calculateFinancialsForScenario = (cfg: GlobalConfig) => {
    // Re-calculate unit costs locally for the scenario
    const tempUc = (() => {
      const { beanPricePerKg, milkPricePerL, iceRatio, takeoutRatio } = cfg.cafe;
      const s = cfg.cafeSupplies;
      const bean = (beanPricePerKg / 1000) * s.beanGrams;
      const milk = (milkPricePerL / 1000) * s.milkMl;
      const water = s.water;
      const ice = s.ice;
      const syrup = s.syrup;
      const getMenuCost = (menu: string, type: string, temp: string) => {
        let ing = bean;
        if (menu === 'am') ing += water; else if (menu === 'lt') ing += milk; else ing += milk + syrup;
        if (temp === 'i') ing += ice;
        let pkg = 0;
        if (type === 'to') {
            pkg = temp === 'h' ? (s.hotCup + s.hotLid + s.stick + s.holder + s.carrier + s.wipe + s.napkin) : (s.iceCup + s.iceLid + s.straw + s.holder + s.carrier + s.wipe + s.napkin);
        } else {
            pkg = s.wipe + s.napkin + s.dishwashing + (temp === 'h' ? s.stick : s.straw);
        }
        return ing + pkg;
      };

      const calcWeighted = (m: 'am' | 'lt' | 'sl') => {
          const toH = getMenuCost(m, 'to', 'h');
          const toI = getMenuCost(m, 'to', 'i');
          const stH = getMenuCost(m, 'st', 'h');
          const stI = getMenuCost(m, 'st', 'i');
          return (toI * iceRatio + toH * (1 - iceRatio)) * takeoutRatio + (stI * iceRatio + stH * (1 - iceRatio)) * (1 - takeoutRatio);
      };
      return {
        finalCostAmericano: calcWeighted('am'),
        finalCostLatte: calcWeighted('lt'),
        finalCostSyrupLatte: calcWeighted('sl'),
      };
    })();

    const fin = calculateFinancials(cfg, tempUc as any);
    return {
      totalRevenue: fin.totalRevenue,
      netProfit: fin.netProfit,
      totalInvestment: fin.totalInvestment
    };
  };

  return (
    <div className="min-h-screen bg-[#fdfcfb] font-sans text-[#3e2723]">
      <header className="bg-white border-b border-orange-100 sticky top-0 z-50 shadow-sm backdrop-blur-md bg-white/90">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center space-x-4">
              <div className="p-2.5 bg-[#5d4037] rounded-xl shadow-lg">
                <Layout className="text-white" size={24} />
              </div>
              <div className="border-l border-orange-100 pl-4 py-1">
                <span className="font-bold text-lg tracking-tight block leading-tight text-[#5d4037]">Terrazza Lounge</span>
                <span className="text-[10px] text-orange-600 font-black uppercase tracking-[0.2em]">Business Planner</span>
              </div>
            </div>

            <nav className="flex space-x-1 bg-orange-50/70 p-1 rounded-xl overflow-x-auto">
              {[
                { id: Tab.DASHBOARD, label: '대시보드', icon: <TrendingUp size={16} /> },
                { id: Tab.PLANNER, label: '상세 설정', icon: <Calculator size={16} /> },
                { id: Tab.COMPARISON, label: '계획 비교', icon: <Copy size={16} /> },
                { id: Tab.STRATEGY, label: 'AI 전략', icon: <Sparkles size={16} /> },
                { id: Tab.TODO, label: '준비물', icon: <CheckSquare size={16} /> },
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as Tab)}
                  className={`flex items-center space-x-2 px-3 sm:px-4 py-2 rounded-lg text-sm font-bold transition-all duration-300 whitespace-nowrap ${activeTab === tab.id ? 'bg-[#5d4037] text-white shadow-md' : 'text-slate-500 hover:text-[#5d4037] hover:bg-white'}`}
                >
                  {tab.icon}
                  <span className="hidden lg:inline">{tab.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>

        <div className="bg-[#fff9f5] border-b border-orange-100 py-2.5">
          <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-4">

            {/* Left Side: Standard Models (Presets) */}
            <div className="flex items-center gap-3 w-full md:w-auto overflow-hidden">
              <span className="text-[10px] font-black text-orange-400 uppercase tracking-widest whitespace-nowrap flex items-center gap-1">
                 <BookTemplate size={12}/> Standard Models:
              </span>
              <div className="flex gap-1.5 overflow-x-auto pb-1 md:pb-0 scrollbar-hide">
                {Object.keys(PLAN_PRESETS).map(name => (
                  <button 
                    key={name}
                    onClick={() => applyPreset(name)}
                    className="px-3 py-1 bg-white border border-orange-200 rounded-lg text-[10px] font-bold text-[#5d4037] hover:bg-orange-50 hover:border-orange-500 transition-all shadow-sm whitespace-nowrap"
                  >
                    {name}
                  </button>
                ))}
              </div>
            </div>

            {/* Right Side: Saved Plans & Draft Actions */}
            <div className="flex items-center gap-3 w-full md:w-auto border-t md:border-t-0 pt-2.5 md:pt-0 border-orange-100">
               <span className="text-[10px] font-black text-orange-400 uppercase tracking-widest whitespace-nowrap flex items-center gap-1">
                 <Copy size={12}/> My Plans:
               </span>

               {/* Saved Scenarios List */}
               <div className="flex gap-1.5 overflow-x-auto scrollbar-hide items-center max-w-[200px] lg:max-w-none">
                {scenarios.map(s => (
                  <div key={s.id} className={`flex items-center bg-white border rounded-lg pl-2 pr-1 h-7 shadow-sm transition-all group ${activeScenarioId === s.id ? 'border-orange-500 bg-orange-50 text-orange-700' : 'border-orange-100 text-slate-600'}`}>
                    <button onClick={() => loadScenario(s.id)} className="text-[10px] font-bold mr-1 whitespace-nowrap">
                      {s.name}
                    </button>
                    <button onClick={(e) => deleteScenario(s.id, e)} className="p-0.5 text-orange-200 hover:text-rose-500 rounded hover:bg-rose-50 transition-colors"><Trash2 size={10} /></button>
                  </div>
                ))}
                {scenarios.length === 0 && <span className="text-[10px] text-gray-400 italic">저장된 계획 없음</span>}
               </div>

                {/* Current Draft Action Buttons */}
                <div className="flex items-center gap-1 ml-2 border-l border-orange-200 pl-3">
                   {/* Reset Button: Contextually placed with current draft actions */}
                   <button 
                      onClick={resetConfig}
                      className="px-2 h-7 bg-slate-100 border border-slate-200 text-slate-500 rounded-lg text-[10px] font-bold flex items-center gap-1 shadow-sm hover:bg-slate-200 transition-all whitespace-nowrap"
                      title="입력값 초기화 (현재 드래프트 비우기)"
                    >
                      <RotateCcw size={10} />
                   </button>

                   {activeScenarioId && (
                    <button 
                      onClick={updateCurrentScenario}
                      className="px-2 h-7 bg-emerald-600 text-white rounded-lg text-[10px] font-bold flex items-center gap-1 shadow-sm hover:bg-emerald-700 transition-all whitespace-nowrap"
                      title="현재 계획 덮어쓰기"
                    >
                      <RefreshCw size={10}/>
                    </button>
                   )}
                   <button 
                    onClick={() => { const name = prompt("새로운 계획 이름을 입력하세요:"); if(name) saveCurrentScenario(name); }} 
                    className="px-3 h-7 bg-[#5d4037] text-white rounded-lg text-[10px] font-bold flex items-center gap-1.5 shadow-sm hover:bg-[#4e342e] transition-all transform hover:-translate-y-0.5 whitespace-nowrap"
                   >
                    <Plus size={12}/> {activeScenarioId ? '새로 저장' : '저장'}
                   </button>
                </div>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 pb-16">
        {activeTab === Tab.DASHBOARD && (
          <DashboardTab 
            monthlyData={monthlyData}
            totalInvestment={currentFinancials.totalInvestment}
            bepMonth={bepMonth}
          />
        )}

        {activeTab === Tab.PLANNER && (
          <PlannerTab 
            config={config}
            onConfigChange={(s, f, v) => setConfig(prev => ({...prev, [s]: {...prev[s], [f]: v}}))}
            onSupplyChange={(f, v) => setConfig(prev => ({...prev, cafeSupplies: {...prev.cafeSupplies, [f]: v}}))}
            monthlyData={monthlyData}
            dailySalesCount={currentFinancials.salesCount}
            cafeUnitCosts={cafeUnitCosts} 
            totalInvestment={currentFinancials.totalInvestment}
            calculatedLaborCost={currentFinancials.laborCost}
          />
        )}

        {/* FIXED: Passed currentConfig to ComparisonTab to allow real-time comparison */}
        {activeTab === Tab.COMPARISON && (
          <ComparisonTab 
            scenarios={scenarios} 
            currentConfig={config}
            calculateFinancials={calculateFinancialsForScenario} 
          />
        )}

        {activeTab === Tab.STRATEGY && (
          <StrategyTab config={config} financials={currentFinancials} bepMonth={bepMonth} />
        )}

        {activeTab === Tab.TODO && (
          <TodoTab todos={todos} onToggle={(id) => setTodos(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t))} />
        )}
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { GlobalConfig } from '../types';
import { 
    BrainCircuit, 
    Sparkles, 
    TrendingUp, 
    ShieldAlert, 
    Target, 
    Lightbulb, 
    Loader2,
    CheckCircle2,
    ArrowRight,
    FileText
} from 'lucide-react';

interface StrategyTabProps {
  config: GlobalConfig;
  financials: any;
  bepMonth: string;
}

export const StrategyTab: React.FC<StrategyTabProps> = ({ config, financials, bepMonth }) => {
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const generateStrategy = async () => {
    setLoading(true);
    setError(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `
        당신은 프리미엄 복합 문화 공간 'Terrazza Lounge'의 전문 비즈니스 컨설턴트입니다. 
        카페, 공간대여, 와인바 3가지 사업이 결합된 현재의 사업 계획을 분석하고 전략적인 조언을 제공해주세요.

        현재 설정 데이터:
        - 카페: 좌석 ${config.cafe.seatCount}개, 일 영업 ${config.cafe.operatingHours}시간, 회전율 ${config.cafe.turnoverTarget*100}%, 테이크아웃 ${config.cafe.takeoutRatio*100}%
