               </div>

                {/* Current Draft Action Buttons */}
                <div className="flex items-center gap-1 ml-2 border-l border-orange-200 pl-3">
                   {/* Reset Button: Contextually placed with current draft actions */}
                   <button 
                      onClick={resetConfig}
